1	import { eq } from "@tanstack/db";
2	import { useLiveQuery } from "@tanstack/react-db";
3	import { createFileRoute, Outlet, useMatchRoute } from "@tanstack/react-router";
4	import { useEffect, useMemo, useRef } from "react";
5	import { useV2UserPreferences } from "renderer/hooks/useV2UserPreferences";
6	import { electronTrpc } from "renderer/lib/electron-trpc";
7	import { useDashboardSidebarState } from "renderer/routes/_authenticated/hooks/useDashboardSidebarState";
8	import { useCollections } from "renderer/routes/_authenticated/providers/CollectionsProvider";
9	import { useHostWorkspaces } from "renderer/routes/_authenticated/providers/HostWorkspacesProvider";
10	import { useWorkspaceTransactionsStore } from "renderer/stores/workspace-creates";
11	import { WorkspaceCreateErrorState } from "./components/WorkspaceCreateErrorState";
12	import { WorkspaceCreatingState } from "./components/WorkspaceCreatingState";
13	import { WorkspaceHostIncompatibleState } from "./components/WorkspaceHostIncompatibleState";
14	import { WorkspaceNotFoundState } from "./components/WorkspaceNotFoundState";
15	import { useRemoteHostStatus } from "./hooks/useRemoteHostStatus";
16	import { WorkspaceProvider } from "./providers/WorkspaceProvider";
17	
18	// Diagnostic logging for the intermittent v2-workspace blank-pane bug.
19	// Emitted as "[agent-dots] ..." so the main-process console-message
20	// forwarder persists it to electron-log (main.log) in a shipped build.
21	// Logging-only — never alters behaviour. See patches/v2-workspace-blank-fix.patch.
22	function blankDbg(record: Record<string, unknown>): void {
23		try {
24			console.info(
25				`[agent-dots] ${JSON.stringify({ ts: new Date().toISOString(), event: "v2_workspace_layout", ...record })}`,
26			);
27		} catch {
28			// never let logging crash the renderer
29		}
30	}
31	
32	export const Route = createFileRoute("/_authenticated/_dashboard/v2-workspace")(
33		{
34			component: V2WorkspaceLayout,
35		},
36	);
37	
38	function V2WorkspaceLayout() {
39		const matchRoute = useMatchRoute();
40		const workspaceMatch = matchRoute({
41			to: "/v2-workspace/$workspaceId",
42		});
43		const workspaceId =
44			workspaceMatch !== false ? workspaceMatch.workspaceId : null;
45		const collections = useCollections();
46		const { placeWorkspaceFromPassiveMount } = useDashboardSidebarState();
47		const pendingTransaction = useWorkspaceTransactionsStore((state) =>
48			workspaceId ? (state.byWorkspaceId[workspaceId] ?? null) : null,
49		);
50		// The create transaction clears when the workspaces.create mutation
51		// settles — not when the host-served row first arrives, which happens
52		// mid-create before agent/terminal panes are seeded.
53		const isCreatePending = pendingTransaction?.type === "insert";
54	
55		// Menu-driven presets bar toggle lives here, above WorkspaceProvider:
56		// workspaceTrpc.Provider (inside it) shares @trpc/react-query's default
57		// context, so electronTrpc hooks below it would resolve the host-service
58		// HTTP client, which does not support subscriptions.
59		const { toggleShowPresetsBar } = useV2UserPreferences();
60		electronTrpc.menu.subscribe.useSubscription(undefined, {
61			onData: (event) => {
62				if (event.type === "toggle-presets-bar") {
63					toggleShowPresetsBar();
64				}
65			},
66		});
67	
68		const { workspaces: hostWorkspaces, isReady, cache } = useHostWorkspaces();
69		const workspace = useMemo(
70			() =>
71				workspaceId != null
72					? (hostWorkspaces.find((candidate) => candidate.id === workspaceId) ??
73						null)
74					: null,
75			[hostWorkspaces, workspaceId],
76		);
77		const { data: failedEntries } = useLiveQuery(
78			(q) =>
79				q
80					.from({ failed: collections.failedWorkspaceCreates })
81					.where(({ failed }) => eq(failed.id, workspaceId ?? "")),
82			[collections, workspaceId],
83		);
84		const failedEntry = failedEntries?.[0] ?? null;
85	
86		const lastEnsuredWorkspaceIdRef = useRef<string | null>(null);
87		useEffect(() => {
88			if (!workspace || lastEnsuredWorkspaceIdRef.current === workspace.id)
89				return;
90			lastEnsuredWorkspaceIdRef.current = workspace.id;
91			// (REMOVE-STICKY) passive mount — must not resurrect a removed project.
92			placeWorkspaceFromPassiveMount(workspace.id, workspace.projectId);
93		}, [placeWorkspaceFromPassiveMount, workspace]);
94	
95		// Cache-first hold (apps/desktop AGENTS.md rule 9): a transient Electric
96		// re-sync can momentarily make the live query return undefined/empty with
97		// isReady=false, which previously blanked an already-rendered workspace
98		// (empty <div/>) until a manual reload. Keep the last resolved workspace
99		// for the current id and reuse it through the transient so panes don't
100		// blank. Ref write during render is a pure idempotent cache update.
101		const lastResolvedWorkspaceRef = useRef<NonNullable<typeof workspace> | null>(
102			null,
103		);
104		if (workspace && workspaceId) {
105			lastResolvedWorkspaceRef.current = workspace;
106		}
107		// Host-served list is always an array (loading is signalled via isReady),
108		// so "data absent" from the old live-query shape maps onto !isReady — PLUS
109		// one gap isReady cannot see: v2Hosts transiently dropping a host's row
110		// (Electric resync) removes that host's query target entirely, leaving
111		// isReady's every() vacuously true while the host's rows are missing from
112		// the merged list. resolveHostUrl(hostId) === null is precisely "no
113		// reachable target for this host right now", so hold through that too
114		// instead of flashing not-found on an open workspace.
115		const heldCandidate =
116			workspaceId && lastResolvedWorkspaceRef.current?.id === workspaceId
117				? lastResolvedWorkspaceRef.current
118				: null;
119		const isTransient =
120			!isReady ||
121			(heldCandidate !== null &&
122				cache.resolveHostUrl(heldCandidate.hostId) === null);
123		const heldWorkspace: typeof workspace =
124			workspace ?? (isTransient ? heldCandidate : null);
125	
126		const hostStatus = useRemoteHostStatus(heldWorkspace);
127	
128		// Diagnostic: log the blank-relevant render decision once per transition
129		// (not per render). Confirms which branch fires and whether the
130		// cache-first hold engaged.
131		const renderBranch = !workspaceId
132			? "no-workspace-id"
133			: !heldWorkspace && !workspace && !isReady
134				? "blank-data-not-ready"
135				: !heldWorkspace
