// Nothing re-renders on wall-clock alone (steady-state refetches
// structural-share into identical data), so an armed missing-clock
// schedules its own deadline re-run — otherwise a genuinely deleted
// branch's card would wait for an unrelated render to be pruned.
if (pruneFirstMissingAtRef.current.size > 0) {
	const earliest = Math.min(...pruneFirstMissingAtRef.current.values());
	const delay = Math.max(
		1_000,
		earliest + PRUNE_MISSING_GRACE_MS - Date.now(),
	);
	const timer = window.setTimeout(
		() => setPruneTick((t) => t + 1),
		delay,
	);
	return () => window.clearTimeout(timer);
}

