4	import { useEffect, useMemo, useState } from "react";
5	import { useRelayUrl } from "renderer/hooks/useRelayUrl";
6	import { getHostServiceWsToken } from "renderer/lib/host-service-auth";
7	import { getHostServiceClientByUrl } from "renderer/lib/host-service-client";
8	import { useCollections } from "renderer/routes/_authenticated/providers/CollectionsProvider";
9	import { useLocalHostService } from "renderer/routes/_authenticated/providers/LocalHostServiceProvider";
10	import {
11		applyWorkspaceChangedEvent,
12		deriveHostWorkspacesQueryTargets,
13		getHostWorkspacesQueryKey,
14		type HostWorkspaceItem,
15		type HostWorkspaceRow,
16		loadHostWorkspacesSnapshot,
17		mergeHostWorkspaces,
18		saveHostWorkspacesSnapshot,
19	} from "./useHostWorkspaces.utils";
20	
21	export type { HostWorkspaceItem } from "./useHostWorkspaces.utils";
22	
23	const WORKSPACES_FALLBACK_REFETCH_INTERVAL_MS = 30_000;
24	
25	export interface HostWorkspacesCacheOps {
26		/** Resolve the URL to reach the host owning `hostId` (null = unreachable). */
27		resolveHostUrl: (hostId: string) => string | null;
28		/**
29		 * Optimistically upsert a row into a host's cached list. The host's
30		 * `workspace:changed` broadcast (or the next refetch) converges the
31		 * cache onto the real row.
32		 */
33		upsertWorkspace: (row: HostWorkspaceRow) => void;
34		/** Optimistically drop a row from a host's cached list. */
35		removeWorkspace: (hostId: string, workspaceId: string) => void;
36		/** Rollback hammer: refetch a host's list after a failed write. */
37		invalidateHost: (hostId: string) => void;
38	}
39	
40	export interface UseHostWorkspacesResult {
41		workspaces: HostWorkspaceItem[];
42		/**
43		 * True once every host answered, failed, or served a snapshot. Gates
44		 * empty states only — existing rows always render (cache-first rule).
45		 */
46		isReady: boolean;
47		/**
48		 * (KANBAN-HOST-SOURCE) True only while EVERY known host's live
49		 * `workspace.list` has data this session (kept through refetch errors).
50		 * The only state in which a row's absence from `workspaces` proves
51		 * deletion when the row's owning host is unknown. Snapshots deliberately
52		 * do NOT count: they are best-effort and possibly stale/empty — they can
53		 * prove presence, never absence. Destructive reactions to a missing row
54		 * must gate on this (or on `isAbsenceAuthoritative` with a known owner),
55		 * never on `isReady`.
56		 */
57		isAuthoritative: boolean;
58		/**
59		 * (KANBAN-HOST-SOURCE) Per-owner absence authority: for a row known to
60		 * belong to `hostId`, absence is proven once THAT host's live list has
61		 * data (unrelated offline hosts don't block), or when the host row was
62		 * removed from the org entirely. Null/undefined owner falls back to the
63		 * global `isAuthoritative`.
64		 */
65		isAbsenceAuthoritative: (hostId: string | null | undefined) => boolean;
66		cache: HostWorkspacesCacheOps;
67	}
68	
69	/**
70	 * The workspace read path: fan out `workspace.list` to every known host
71	 * (local direct, remote via relay), merge, live-update from each host's
72	 * `workspace:changed` events, and persist last-seen lists per host to
73	 * IndexedDB so remote machines still render offline.
74	 *
75	 * Cloud rows from the still-synced Electric collection fill in only for
76	 * hosts that served nothing (pre-R1 builds, no snapshot) — that fallback
77	 * disappears in R3.
78	 *
79	 * Runs once inside HostWorkspacesProvider; consumers read the shared
80	 * result via that provider's useHostWorkspaces.
81	 */
82	export function useHostWorkspacesSource(): UseHostWorkspacesResult {
83		const collections = useCollections();
84		const queryClient = useQueryClient();
85		const { activeHostUrl, machineId } = useLocalHostService();
86		const relayUrl = useRelayUrl();
87	
88		const { data: hosts = [] } = useLiveQuery(
89			(q) =>
90				q.from({ hosts: collections.v2Hosts }).select(({ hosts }) => ({
91					organizationId: hosts.organizationId,
92					machineId: hosts.machineId,
